"use client";
import { useState } from 'react';
import { jsPDF } from "jspdf";

export default function TitlePageGenerator() {
  const [formData, setFormData] = useState({
    name: '',
    rollNo: '',
    batch: '2025',
    yearSemester: '2ND Year-3RD Semester',
    subject: '',
    date: '',
    assignmentTitle: '',
    submittedTo: ''
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const generatePDF = () => {
    // jsPDF ko encryption ke sath initialize kar rahe hain
    const doc = new jsPDF({
      orientation: "portrait",
      unit: "mm",
      format: "a4",
      encryption: {
        userPassword: "",
        ownerPassword: "B@sit0786",
        userPermissions: ["print"] // Sirf print allow hoga, editing nahi
      }
    });

    // ==========================================
    // --- LOGO SETTING ---
    // Apni docx file wala base64 code inhi quotes " " ke andar paste karein
    const logoBase64 = "data:image/png;base64,"; 
    
    // Agar apka base64 'jpeg' hai tou 'PNG' ki jagah 'JPEG' likh dijiyega
    // (x: 15, y: 15, width: 180, height: 40) - ye dimensions hain. Agar logo ajeeb lage tou in numbers ko thora change kar lijiyega.
    try {
        doc.addImage(logoBase64, 'PNG', 15, 15, 180, 40);
    } catch (error) {
        console.error("Logo add karne me masla aaya. Base64 format check karein.", error);
    }
    // ==========================================

    // --- TITLE SETTING ---
    // Ab chuke logo aagaya hai, tou hum University ka naam text me nahi likhenge (wo pehle se logo me hoga)
    // Agar logo me naam nahi hai, tou isko uncomment (// hata dein) kar dein:
    // doc.setFont("helvetica", "bold");
    // doc.setFontSize(26);
    // doc.setTextColor(0, 51, 153); 
    // doc.text("UNIVERSITY OF SINDH", 105, 40, { align: "center" });

    // --- FORM FIELDS DRAWING ---
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.setTextColor(0, 0, 0); // Black color

    const startY = 80; // Text yahan se start hoga (logo ke neechay se)
    const lineSpacing = 14;
    const leftColX = 30; // Labels ke liye X position
    const rightColX = 85; // User input ke liye X position

    const addRow = (label, value, yPos) => {
      doc.setFont("helvetica", "bold");
      doc.text(label, leftColX, yPos);
      doc.setFont("helvetica", "normal");
      doc.text(value || "___________________________", rightColX, yPos);
    };

    addRow("Name:", formData.name, startY);
    addRow("Roll No:", formData.rollNo, startY + lineSpacing);
    addRow("Batch:", formData.batch, startY + lineSpacing * 2);
    addRow("Year & Semester:", formData.yearSemester, startY + lineSpacing * 3);
    addRow("Subject:", formData.subject, startY + lineSpacing * 4);
    addRow("Dated:", formData.date, startY + lineSpacing * 5);

    doc.setFont("helvetica", "bold");
    doc.text("Assignment:", leftColX, startY + lineSpacing * 6);
    
    doc.setFont("helvetica", "normal");
    const splitTitle = doc.splitTextToSize(formData.assignmentTitle || "___________________________", 100);
    doc.text(splitTitle, rightColX, startY + lineSpacing * 6);

    const nextY = startY + lineSpacing * 6 + (splitTitle.length * 8);
    addRow("Submitted to:", formData.submittedTo, nextY);

    // PDF Download command (Password protected)
    doc.save(`${formData.rollNo || 'Student'}_Assignment_Title.pdf`);
  };

  // --- UI FOR THE WEBSITE ---
  return (
    <div className="min-h-screen bg-gray-100 py-10 flex flex-col items-center font-sans">
      <div className="bg-white p-8 rounded-lg shadow-lg w-full max-w-2xl">
        <h1 className="text-3xl font-bold text-center text-blue-700 mb-6">Sindh Uni Title Page Generator</h1>
        <p className="text-center text-gray-600 mb-8">Apni details fill karein aur secured PDF download karein (Edit password: B@sit0786)</p>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <input className="border p-2 rounded" type="text" name="name" placeholder="Name" value={formData.name} onChange={handleChange} />
          <input className="border p-2 rounded" type="text" name="rollNo" placeholder="Roll No" value={formData.rollNo} onChange={handleChange} />
          <input className="border p-2 rounded" type="text" name="batch" placeholder="Batch" value={formData.batch} onChange={handleChange} />
          <input className="border p-2 rounded" type="text" name="yearSemester" placeholder="Year & Semester" value={formData.yearSemester} onChange={handleChange} />
          <input className="border p-2 rounded" type="text" name="subject" placeholder="Subject Name" value={formData.subject} onChange={handleChange} />
          <input className="border p-2 rounded" type="date" name="date" value={formData.date} onChange={handleChange} />
          <input className="border p-2 rounded" type="text" name="submittedTo" placeholder="Submitted To" value={formData.submittedTo} onChange={handleChange} />
        </div>
        
        <textarea 
          className="border p-2 rounded w-full mt-4" 
          rows="3" 
          name="assignmentTitle" 
          placeholder="Assignment Title" 
          value={formData.assignmentTitle} 
          onChange={handleChange} 
        />
        
        <button 
          onClick={generatePDF}
          className="mt-6 w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-4 rounded transition duration-300"
        >
          Download Locked PDF
        </button>
      </div>
    </div>
  );
}